shortcuts.codeOnPrepare:
{
// 1. Get Variable
const rawUrl = getVariable(/*[variable]*/"d3647ed4-8dee-4ec9-aed3-cb814c9fe80f"/*[/variable]*/);

// 2. decodeURIComponent, change %3A to :，%2F to /, so on so forth.
const decodedUrl = decodeURIComponent(rawUrl);

// 3. (Optional) Use trim() to remove additional space.
let finalUrl = decodedUrl.trim();

// 4. Store back to url.
setVariable(/*[variable]*/"d3647ed4-8dee-4ec9-aed3-cb814c9fe80f"/*[/variable]*/, finalUrl);

}

shortcuts.codeOnSuccess:
{

    // =================================================================
    // 0. Initialization
    // =================================================================
    const inputUrl = getVariable(/*[variable]*/"d3647ed4-8dee-4ec9-aed3-cb814c9fe80f"/*[/variable]*/);
    let finalUrl = inputUrl; 
    let html = "";

    try {
        if (typeof response !== 'undefined' && response) {
            if (response.url) finalUrl = response.url;
            html = response.body;
        }
    } catch (e) {}

    // =================================================================
    // ⚔️ Parse the Googlr page for short url.
    // =================================================================
    if (finalUrl.indexOf("goo.gl") !== -1 || finalUrl.indexOf("app.goo.gl") !== -1) {
        if (html) {
            showToast ("Still short url ");
            const deepLinkMatch = html.match(/https:\/\/www\.google\.com\/maps\/[^"]+/);
            if (deepLinkMatch) {
                finalUrl = deepLinkMatch[0];
            }
        }
    }

    // =================================================================
    // 🔑 Global URL Decode
    // =================================================================
    try {
        finalUrl = decodeURIComponent(finalUrl);
    } catch (e) {
        showDialog ("Decode failed");
    }
    // 🛑 Checkpoint
    if (finalUrl.indexOf("http") === -1) {
        showDialog("Error", "Invalid URL！\nCurrent contents " + finalUrl);
        throw new Error("Invalid URL");
    }

    // =================================================================
    // 1. Position Extraction
    // =================================================================
    let lat = "";
    let lon = "";
    let name = "";

    // Get !3d...!4d...
    const dataMatch = finalUrl.match(/!3d(-?\d+\.\d+)!4d(-?\d+\.\d+)/);
    if (dataMatch) {
        lat = dataMatch[1];
        lon = dataMatch[2];
    } else {
        // Use regex to get @lat,lon
        const atMatch = finalUrl.match(/@(-?\d+\.\d+),(-?\d+\.\d+)/);
        if (atMatch) {
            lat = atMatch[1];
            lon = atMatch[2];
        }
    }

    // =================================================================
    // 2. PoiName Extraction
    // =================================================================
    // Plan A: HTML Meta Tag
    if (html) {
        try {
            const metaMatch = html.match(/meta\s+(?:content="([^"]+)"\s+property="og:title"|property="og:title"\s+content="([^"]+)")/);
            if (metaMatch) name = metaMatch[1] || metaMatch[2];
                if (!(!name || name === "Google Maps" || name === ""))
                    showToast ("Get poi_name from og:title "+name);
        } catch (e) {}
    }

    // Plan B: URL Reversion Extraction
    if (!name || name === "Google Maps") {
        const placeMatch = finalUrl.match(/\/place\/([^\/]+)/);
        if (placeMatch) {
            let rawName = placeMatch[1];

            rawName = rawName.replace(/\+/g, " ");
            rawName = rawName.replace(/[,，].*$/, "");
            rawName = rawName.replace(/^\d+.*?[號樓Ff]/, "");
            name = rawName.trim();
            showToast ("Get poi_name from Url "+name);
        }
    }

    // =================================================================
    // 3. Navigate to Amap
    // =================================================================
    if (lat && lon) {
        if (!name || name === "Google Maps" || name === "") name = lat + "," + lon;

        const amapUrl = "androidamap://viewMap?sourceApplication=HTTPShortcuts&poiname=" + encodeURIComponent(name) + "&lat=" + lat + "&lon=" + lon + "&dev=1";

        openUrl(amapUrl);
    } else {
        showDialog("解析失敗", "找不到座標。\nFinalURL (Decoded): ");
    }

}
